const owner = $env.GITHUB_REPO_OWNER || "kreativmonkey";
const repo = $env.GITHUB_REPO_NAME || "homelab-gitops";
const token = $env.GITHUB_TOKEN;
const autoMergeUsers = ["renovate[bot]"];
const api = ($env.GITHUB_API_URL || "https://api.github.com").replace(/\/$/, "");
const baseUrl = api + "/repos/" + owner + "/" + repo;
const headers = { Authorization: "Bearer " + token, Accept: "application/vnd.github+json" };
const PROCESSED_LABEL = "auto-merge-done";

async function gh(path, opts) {
  opts = opts || {};
  return this.helpers.httpRequest({
    method: opts.method || "GET",
    url: baseUrl + path,
    headers: headers,
    json: true,
    body: opts.body || undefined,
    timeout: 30000,
  });
}

async function addLabel(prNum) {
  try {
    await gh("/issues/" + prNum + "/labels", {
      method: "POST",
      body: { labels: [PROCESSED_LABEL] },
    });
  } catch (_) { /* ignore label errors */ }
}

const prs = await gh("/pulls?state=open&per_page=50");
const results = [];

for (const pr of prs) {
  const author = pr.user.login;
  const labels = (pr.labels || []).map(function(l) { return l.name; });

  // Skip PRs already processed
  if (labels.indexOf(PROCESSED_LABEL) !== -1) continue;

  // Skip if mergeable status unknown (GitHub still computing)
  if (pr.mergeable === null) continue;

  // --- Non-auto-merge: notify once, then label ---
  if (autoMergeUsers.indexOf(author) === -1) {
    results.push({
      telegramText: "👤 *PR #" + pr.number + "* by @" + author + "\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    await addLabel(pr.number);
    continue;
  }

  // --- Auto-merge candidate ---

  // Check merge conflicts
  if (pr.mergeable === false) {
    results.push({
      telegramText: "🚫 *PR #" + pr.number + "* merge conflict (" + author + ")\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    await addLabel(pr.number);
    continue;
  }

  // Check CI status
  const checks = await gh("/commits/" + pr.head.sha + "/check-runs");
  const hasFailure = checks.check_runs.some(function(c) { return c.conclusion === "failure"; });
  const allSuccess = checks.check_runs.every(function(c) { return c.conclusion === "success"; });

  if (!allSuccess) {
    results.push({
      telegramText: "⏳ *PR #" + pr.number + "* CI "
        + (hasFailure ? "failed" : "pending") + " (" + author + ")\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    if (hasFailure) await addLabel(pr.number); // Stop retrying on failure
    continue; // Pending: no label, will retry
  }

  // CI passes, mergeable -> attempt merge
  try {
    await gh("/pulls/" + pr.number + "/merge", {
      method: "PUT",
      body: { merge_method: "squash" },
    });
    results.push({
      telegramText: "✅ *PR #" + pr.number + " merged*\n"
        + (pr.title || "") + "\n"
        + "_by " + author + "_",
      parseMode: "Markdown",
    });
  } catch (e) {
    results.push({
      telegramText: "❌ *PR #" + pr.number + " merge failed*\n"
        + (pr.title || "") + "\n"
        + "_by " + author + "_\n"
        + String(e.message || e).slice(0, 200),
      parseMode: "Markdown",
    });
  }
  await addLabel(pr.number);
}

if (results.length === 0) {
  results.push({
    telegramText: "ℹ️ *PR check*: No unprocessed PRs",
    parseMode: "Markdown",
  });
}

return results.map(function(r) { r.chatId = $env.TELEGRAM_CHAT_ID; return { json: r }; });
